// HasSalesReturn applies the HasEdge predicate on the "sales_return" edge.
func HasSalesReturn() predicate.SalesReturnItem {
	return predicate.SalesReturnItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SalesReturnTable, SalesReturnColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSalesReturnWith applies the HasEdge predicate on the "sales_return" edge with a given conditions (other predicates).
func HasSalesReturnWith(preds ...predicate.SalesReturn) predicate.SalesReturnItem {
	return predicate.SalesReturnItem(func(s *sql.Selector) {
		step := newSalesReturnStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SalesReturnItem) predicate.SalesReturnItem {
	return predicate.SalesReturnItem(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SalesReturnItem) predicate.SalesReturnItem {
	return predicate.SalesReturnItem(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SalesReturnItem) predicate.SalesReturnItem {
	return predicate.SalesReturnItem(sql.NotPredicates(p))
}
